function getLocaleAwareUiFontFamily() {
    const lang = String(document.documentElement?.lang || navigator.language || '').trim().toLowerCase();
    if (lang.startsWith('ja')) {
        return IBM_UI_FONT_FAMILY_JA;
    }
    return IBM_UI_FONT_FAMILY_KO;
}

