function isChatToolsOverlayOpen() {
    const overlay = document.getElementById('codex-chat-tools-overlay');
    return overlay ? overlay.classList.contains('is-visible') : false;
}

function getActiveWorktreeTaskCount() {
    return (Array.isArray(state.worktreeTasks) ? state.worktreeTasks : [])
        .map(normalizeWorktreeTask)
        .filter(task => task && task.status === 'active')
        .length;
}

function syncChatToolsToggleState() {
    const button = document.getElementById('codex-chat-tools-toggle');
    if (!button) return;
    const activeWorktreeCount = getActiveWorktreeTaskCount();
    const appServerActive = Boolean(
        state.settings.appServerPilotEnabled
        || state.appServer.status?.remote_control?.running
    );
    const hasActiveState = getWorktreeModeState() || activeWorktreeCount > 0 || appServerActive;
    const labelParts = [];
    if (activeWorktreeCount > 0) {
        labelParts.push(`${activeWorktreeCount} worktree`);
    }
    if (appServerActive) {
        labelParts.push('App Server');
    }
    const label = labelParts.length > 0
        ? `추가 도구 열기 (${labelParts.join(', ')})`
        : '추가 도구 열기';
    button.classList.toggle('is-active', hasActiveState);
    button.setAttribute('aria-label', label);
    button.setAttribute('title', label);
}

function openChatToolsOverlay() {
    const elements = getChatToolsOverlayElements();
    if (!elements) return;
    if (isGitBranchOverlayOpen()) {
        closeGitBranchOverlay();
    }
    if (isGitSyncOverlayOpen()) {
        closeGitSyncOverlay();
    }
    if (isMessageLogOverlayOpen()) {
        closeMessageLogOverlay();
    }
    if (isFileBrowserOverlayOpen()) {
        closeFileBrowserOverlay();
    }
    if (isMailComposeOverlayOpen()) {
        closeMailComposeOverlay();
    }
    if (isMobileSessionOverlayOpen()) {
        closeMobileSessionOverlay();
    }
    if (isUsageHistoryOverlayOpen()) {
        closeUsageHistoryOverlay();
    }
    if (isTerminalOverlayOpen()) {
        closeTerminalOverlay();
    }
    renderExecutionPolicyStrip();
    renderStructuredReportBar();
    renderWorktreeTaskBar();
    renderAppServerPilot();
    renderToolingPanels();
    void ensureToolingPreviewData();
    elements.overlay.classList.add('is-visible');
    elements.overlay.setAttribute('aria-hidden', 'false');
    if (elements.trigger) {
        elements.trigger.setAttribute('aria-expanded', 'true');
    }
    document.body.classList.add('is-overlay-open');
    initializeChatToolsHelp();
    syncChatToolsToggleState();
}

function closeChatToolsOverlay() {
    const elements = getChatToolsOverlayElements();
    if (!elements) return;
    elements.overlay.classList.remove('is-visible');
    elements.overlay.setAttribute('aria-hidden', 'true');
    hideHoverTooltipLayer();
    if (elements.trigger) {
        elements.trigger.setAttribute('aria-expanded', 'false');
    }
    if (
        !isGitBranchOverlayOpen()
        && !isGitSyncOverlayOpen()
        && !isMessageLogOverlayOpen()
        && !isFileBrowserOverlayOpen()
        && !isMailComposeOverlayOpen()
        && !isMobileSessionOverlayOpen()
        && !isUsageHistoryOverlayOpen()
        && !isTerminalOverlayOpen()
    ) {
        document.body.classList.remove('is-overlay-open');
    }
    syncChatToolsToggleState();
}

function getWorktreeModeState() {
    return Boolean(state.worktreeMode);
}

function setWorktreeModeToggleState(nextState) {
    const enabled = Boolean(nextState);
    state.worktreeMode = enabled;
    const button = document.getElementById('codex-worktree-mode-toggle');
    if (!button) return;
    const label = enabled ? 'Worktree mode on' : 'Worktree mode off';
    button.classList.toggle('is-active', enabled);
    button.setAttribute('aria-pressed', enabled ? 'true' : 'false');
    button.setAttribute('aria-label', label);
    setChatToolHelp(button, 'worktreeToggle');
    syncChatToolsToggleState();
}

function normalizeWorktreeTask(task) {
    if (!task || typeof task !== 'object') return null;
    const id = typeof task.id === 'string' ? task.id.trim() : '';
    const path = typeof task.path === 'string' ? task.path.trim() : '';
    if (!id || !path) return null;
    const changedCount = Number(task.changed_files_count);
    return {
        ...task,
        id,
        path,
        branch: typeof task.branch === 'string' ? task.branch.trim() : '',
        status: typeof task.status === 'string' ? task.status.trim() : 'active',
        dirty: Boolean(task.dirty),
        changed_files_count: Number.isFinite(changedCount) ? Math.max(0, changedCount) : 0
    };
}

function renderWorktreeTaskBar() {
    const bar = document.getElementById('codex-worktree-task-bar');
    if (!bar) return;
    const tasks = (Array.isArray(state.worktreeTasks) ? state.worktreeTasks : [])
        .map(normalizeWorktreeTask)
        .filter(task => task && task.status === 'active');
    bar.innerHTML = '';
    bar.classList.toggle('is-hidden', tasks.length === 0);
    tasks.slice(0, 4).forEach(task => {
        const item = document.createElement('div');
        item.className = 'worktree-task-chip';
        const text = document.createElement('span');
        text.className = 'worktree-task-chip-text';
        const count = Number(task.changed_files_count) || 0;
        const branch = task.branch || task.id;
        text.textContent = `${branch} · ${count} file${count === 1 ? '' : 's'}`;
        setHoverTooltip(text, `${CHAT_TOOL_HELP_TEXT.worktreeTask} 경로: ${task.path}`);
        item.appendChild(text);

        const handoff = document.createElement('button');
        handoff.type = 'button';
        handoff.className = 'worktree-task-action';
        handoff.textContent = 'Handoff';
        setChatToolHelp(handoff, 'worktreeHandoff');
        handoff.addEventListener('click', event => {
            event.preventDefault();
            void handoffWorktreeTask(task.id);
        });
        item.appendChild(createChatToolActionGroup(handoff, 'worktreeHandoff'));

        const cleanup = document.createElement('button');
        cleanup.type = 'button';
        cleanup.className = 'worktree-task-action';
        cleanup.textContent = 'Cleanup';
        setChatToolHelp(cleanup, 'worktreeCleanup');
        cleanup.addEventListener('click', event => {
            event.preventDefault();
            void cleanupWorktreeTask(task.id, { force: false });
        });
        item.appendChild(createChatToolActionGroup(cleanup, 'worktreeCleanup'));
        bar.appendChild(item);
    });
    syncChatToolsToggleState();
}

async function refreshWorktreeTasks({ silent = false } = {}) {
    try {
        const result = await fetchJson('/api/codex/worktrees', {
            timeoutMs: GIT_STATUS_REQUEST_TIMEOUT_MS
        });
        state.worktreeTasks = Array.isArray(result?.worktrees)
            ? result.worktrees.map(normalizeWorktreeTask).filter(Boolean)
            : [];
        state.worktreeTasksLoadedAt = Date.now();
        renderWorktreeTaskBar();
        return state.worktreeTasks;
    } catch (error) {
        if (!silent) {
            showToast(`worktree 목록 조회 실패: ${normalizeError(error, 'worktree list failed')}`, {
                tone: 'error',
                durationMs: 4200
            });
        }
        renderWorktreeTaskBar();
        return state.worktreeTasks;
    }
}

async function handoffWorktreeTask(taskId) {
    if (!taskId) return;
    try {
        const result = await fetchJson(`/api/codex/worktrees/${encodeURIComponent(taskId)}/handoff`, {
            method: 'POST',
            timeoutMs: GIT_STATUS_REQUEST_TIMEOUT_MS
        });
        const task = normalizeWorktreeTask(result?.task);
        const changedCount = Number(task?.changed_files_count) || 0;
        showToast(`worktree handoff: ${task?.branch || taskId} · ${changedCount} file${changedCount === 1 ? '' : 's'}`, {
            tone: 'success',
            durationMs: 4200
        });
        await refreshWorktreeTasks({ silent: true });
    } catch (error) {
        showToast(`worktree handoff 실패: ${normalizeError(error, 'handoff failed')}`, {
            tone: 'error',
            durationMs: 5200
        });
    }
}

async function cleanupWorktreeTask(taskId, { force = false } = {}) {
    if (!taskId) return;
    try {
        await fetchJson(`/api/codex/worktrees/${encodeURIComponent(taskId)}`, {
            method: 'DELETE',
            headers: { 'Content-Type': 'application/json' },
            timeoutMs: GIT_COMMIT_REQUEST_TIMEOUT_MS,
            body: JSON.stringify({ force: Boolean(force) })
        });
        showToast('worktree cleanup 완료', { tone: 'success', durationMs: 2600 });
        await refreshWorktreeTasks({ silent: true });
    } catch (error) {
        const payload = error?.payload || {};
        if (!force && payload?.error_code === 'worktree_dirty') {
            const confirmed = window.confirm('worktree에 변경사항이 있습니다. 변경을 버리고 cleanup할까요?');
            if (confirmed) {
                await cleanupWorktreeTask(taskId, { force: true });
            }
            return;
        }
        showToast(`worktree cleanup 실패: ${normalizeError(error, 'cleanup failed')}`, {
            tone: 'error',
            durationMs: 5200
        });
    }
}

async function queuePromptOnServer(
    sessionId,
    prompt,
    { planMode = false, attachments = [], structuredReportPreset = '', worktreeMode = false } = {}
) {
    if (!sessionId) {
        return { ok: false, reason: 'missing_session' };
    }
    const normalizedAttachments = Array.isArray(attachments)
        ? attachments.map(normalizeChatAttachment).filter(Boolean)
        : [];
    const result = await fetchEncryptedChatPromptJson(
        `/api/codex/sessions/${sessionId}/message/queue`,
        {
            prompt,
            plan_mode: Boolean(planMode),
            structured_report_preset: structuredReportPreset || '',
            worktree_mode: Boolean(worktreeMode) && !structuredReportPreset,
            attachments: normalizedAttachments
        }
    );

    const queueCount = Number.isFinite(Number(result?.queue_count))
        ? Math.max(0, Number(result.queue_count))
        : 0;
    if (Array.isArray(result?.pending_queue)) {
        syncSessionPendingQueue(sessionId, result.pending_queue);
    }
    if (result?.started && result?.stream_id) {
        processStartedStreamResponse(
            sessionId,
            prompt,
            result,
            Date.now(),
            resolveRequestResponseMetadata({
                planMode,
                responseMode: result?.response_mode,
                responseModel: result?.response_model,
                responseReasoningEffort: result?.response_reasoning_effort,
                structuredReportPreset,
                worktreeTask: result?.worktree_task || null
            })
        );
        return {
            ok: true,
            reason: 'started',
            sessionId,
            queueCount
        };
    }
    return {
        ok: true,
        reason: 'queued',
        sessionId,
        queueCount,
        activeStreamId: result?.active_stream_id || null
    };
}

async function queuePromptWithPlanMode(
    sessionId,
    prompt,
    planModeState = getPlanModeState(),
    { attachments = [], worktreeMode = getWorktreeModeState() } = {}
) {
    const normalizedPrompt = String(prompt || '').trim();
    if (!sessionId || !normalizedPrompt) {
        return {
            addedCount: 0,
            totalQueued: 0,
            lastResult: null
        };
    }
    const normalizedPlanModeState = normalizePlanModeState(planModeState);
    const queueItems = [];
    if (normalizedPlanModeState === PLAN_MODE_STATE_PLAN_AND_EXECUTE) {
        queueItems.push({ prompt: normalizedPrompt, planMode: true, attachments });
        queueItems.push({ prompt: PLAN_MODE_AUTO_EXECUTE_PROMPT, planMode: false });
    } else {
        queueItems.push({
            prompt: normalizedPrompt,
            planMode: normalizedPlanModeState === PLAN_MODE_STATE_PLAN_ONLY,
            attachments
        });
    }

    let lastResult = null;
    let totalQueued = 0;
    for (const item of queueItems) {
        lastResult = await queuePromptOnServer(sessionId, item.prompt, {
            planMode: item.planMode,
            attachments: item.attachments || [],
            worktreeMode
        });
        const queueCount = Number(lastResult?.queueCount);
        if (Number.isFinite(queueCount)) {
            totalQueued = Math.max(0, queueCount);
        }
    }
    return {
        addedCount: queueItems.length,
        totalQueued,
        lastResult
    };
}

function setPlanModeToggleState(nextState) {
    const normalized = normalizePlanModeState(nextState);
    state.settings.planModeState = normalized;
    const button = document.getElementById('codex-plan-mode-toggle');
    if (!button) return;
    const isActive = normalized !== PLAN_MODE_STATE_OFF;
    const isPlanAndExecute = normalized === PLAN_MODE_STATE_PLAN_AND_EXECUTE;
    button.classList.toggle('is-active', isActive);
    button.classList.toggle('is-plan-and-execute', isPlanAndExecute);
    button.setAttribute('aria-pressed', String(isActive));
    let label = 'Plan mode off';
    let buttonText = 'Plan';
    if (normalized === PLAN_MODE_STATE_PLAN_ONLY) {
        label = 'Plan mode on (planning only)';
    } else if (isPlanAndExecute) {
        label = 'Plan then execute mode on';
        buttonText = 'Plan+';
    }
    button.dataset.planModeState = normalized;
    button.textContent = buttonText;
    button.setAttribute('aria-label', label);
    button.setAttribute('title', label);
}

function getExecutionPolicyPreset(id) {
    const targetId = typeof id === 'string' ? id.trim() : '';
    return (Array.isArray(state.settings.executionPolicyPresets) ? state.settings.executionPolicyPresets : [])
        .find(item => item.id === targetId) || null;
}

function renderExecutionPolicyStrip() {
    const strip = document.getElementById('codex-execution-policy-strip');
    if (!strip) return;
    const standard = getExecutionPolicyPreset('standard');
    const worktree = getExecutionPolicyPreset('worktree_isolated');
    const report = getExecutionPolicyPreset('read_only_ephemeral');
    const presets = [standard, worktree, report].filter(Boolean);
    if (presets.length === 0) {
        strip.classList.add('is-hidden');
        strip.textContent = '';
        return;
    }
    strip.classList.remove('is-hidden');
    strip.innerHTML = '';
    presets.forEach(preset => {
        const pill = document.createElement('span');
        pill.className = 'execution-policy-pill';
        pill.setAttribute('role', 'listitem');
        if (preset.id === 'standard') {
            pill.classList.add('is-active');
        }
        const parts = [
            preset.label,
            preset.sandbox,
            preset.approval ? `approval ${preset.approval}` : '',
            preset.ephemeral ? 'ephemeral' : ''
        ].filter(Boolean);
        pill.textContent = parts.join(' · ');
        const risk = preset.risk ? `Risk ${preset.risk}. ` : '';
        const scope = preset.scope ? `Scope ${preset.scope}. ` : '';
        const fallback = `${risk}${scope}${preset.sandbox || ''}`.trim();
        setChatToolHelp(pill, getExecutionPolicyHelpKey(preset.id), fallback);
        strip.appendChild(pill);
    });
}

function renderStructuredReportBar() {
    const bar = document.getElementById('codex-structured-report-bar');
    if (!bar) return;
    const presets = Array.isArray(state.settings.structuredReportPresets)
        ? state.settings.structuredReportPresets
        : [];
    bar.innerHTML = '';
    bar.classList.toggle('is-hidden', presets.length === 0);
    presets.forEach(preset => {
        const button = document.createElement('button');
        button.type = 'button';
        button.className = 'structured-report-button';
        button.dataset.structuredReportPreset = preset.id;
        button.textContent = preset.label;
        const title = preset.description || preset.defaultPrompt || preset.label;
        button.setAttribute('aria-label', title);
        setChatToolHelp(button, getStructuredReportHelpKey(preset.id), title);
        button.addEventListener('click', event => {
            event.preventDefault();
            void handleStructuredReportPreset(preset.id);
        });
        const group = createChatToolActionGroup(button, getStructuredReportHelpKey(preset.id), title);
        group.classList.add('structured-report-action');
        bar.appendChild(group);
    });
}

function normalizeAppServerStatus(status) {
    if (!status || typeof status !== 'object') {
        return null;
    }
    const remote = status.remote_control && typeof status.remote_control === 'object'
        ? status.remote_control
        : {};
    return {
        pilot_enabled: Boolean(status.pilot_enabled),
        codex_available: status.codex_available !== false,
        remote_control: {
            running: Boolean(remote.running),
            pid: Number.isFinite(Number(remote.pid)) ? Number(remote.pid) : null,
            started_at: remote.started_at || null,
            stopped_at: remote.stopped_at || null,
            last_error: typeof remote.last_error === 'string' ? remote.last_error : '',
            last_exit_code: Number.isFinite(Number(remote.last_exit_code)) ? Number(remote.last_exit_code) : null
        },
        allowed_methods: Array.isArray(status.allowed_methods) ? status.allowed_methods : [],
        read_methods: Array.isArray(status.read_methods) ? status.read_methods : [],
        poc_methods: Array.isArray(status.poc_methods) ? status.poc_methods : []
    };
}

function normalizeAppServerList(value) {
    return Array.isArray(value) ? value.filter(item => item && typeof item === 'object') : [];
}

function getAppServerThreadId(thread) {
    return String(thread?.id || thread?.threadId || thread?.thread_id || '').trim();
}

function getAppServerThreadTitle(thread) {
    return thread?.name || thread?.title || thread?.preview || getAppServerThreadId(thread) || 'thread';
}

function getAppServerNextCursor(payload) {
    return String(payload?.next_cursor || payload?.nextCursor || '').trim();
}

function resetAppServerThreadDetail() {
    state.appServer.selectedThreadId = '';
    state.appServer.threadDetail = null;
    state.appServer.threadDetailTurns = [];
    state.appServer.threadDetailNextCursor = '';
    state.appServer.threadDetailIncludeTurns = false;
    state.appServer.threadLifecyclePreview = null;
    state.appServer.threadDetailLoading = false;
    state.appServer.threadDetailError = '';
}

function buildAppServerThreadsUrl({ cursor = '', searchTerm = '' } = {}) {
    const params = new URLSearchParams();
    params.set('limit', '20');
    params.set('include_exec', '1');
    const normalizedCursor = String(cursor || '').trim();
    if (normalizedCursor) {
        params.set('cursor', normalizedCursor);
    }
    const normalizedSearch = String(searchTerm || '').trim();
    if (normalizedSearch) {
        params.set('search', normalizedSearch);
    }
    return `/api/codex/app-server/threads?${params.toString()}`;
}

function applyAppServerThreadsPayload(payload, cursor = '', { pushCursor = false, resetStack = false } = {}) {
    if (resetStack) {
        state.appServer.threadCursorStack = [];
    } else if (pushCursor) {
        state.appServer.threadCursorStack = [
            ...state.appServer.threadCursorStack,
            state.appServer.threadCursor || ''
        ].slice(-20);
    }
    state.appServer.threadCursor = String(cursor || '').trim();
    state.appServer.threadNextCursor = getAppServerNextCursor(payload);
    state.appServer.threads = normalizeAppServerList(payload?.threads);
    const selectedId = state.appServer.selectedThreadId;
    if (selectedId && !state.appServer.threads.some(thread => getAppServerThreadId(thread) === selectedId)) {
        resetAppServerThreadDetail();
    }
}

function formatAppServerJson(value, maxChars = 7000) {
    let text = '';
    try {
        text = JSON.stringify(value, null, 2);
    } catch (error) {
        text = String(value || '');
    }
    if (text.length <= maxChars) {
        return text;
    }
    return `${text.slice(0, maxChars)}\n... truncated ...`;
}

function renderAppServerPilot() {
    const enabled = Boolean(state.settings.appServerPilotEnabled);
    const status = normalizeAppServerStatus(state.appServer.status);
    const remote = status?.remote_control || {};
    const toggle = document.getElementById('codex-app-server-pilot-toggle');
    const statusElement = document.getElementById('codex-app-server-status');
    const startBtn = document.getElementById('codex-app-server-start');
    const stopBtn = document.getElementById('codex-app-server-stop');
    const refreshBtn = document.getElementById('codex-app-server-refresh');
    const busy = Boolean(state.appServer.loading);
    const errorText = typeof state.appServer.error === 'string' ? state.appServer.error.trim() : '';

    if (toggle) {
        toggle.classList.toggle('is-active', enabled);
        toggle.setAttribute('aria-pressed', enabled ? 'true' : 'false');
        const label = enabled ? 'App Server pilot on' : 'App Server pilot off';
        toggle.setAttribute('aria-label', label);
        setChatToolHelp(toggle, 'appServerPilot');
    }
    if (startBtn) startBtn.disabled = !enabled || busy || Boolean(remote.running);
    if (stopBtn) stopBtn.disabled = !enabled || busy || !remote.running;
    if (refreshBtn) refreshBtn.disabled = !enabled || busy;
    setChatToolHelp(startBtn, 'appServerStart');
    setChatToolHelp(stopBtn, 'appServerStop');
    setChatToolHelp(refreshBtn, 'appServerRefresh');

    if (statusElement) {
        statusElement.classList.toggle('is-error', Boolean(errorText));
        if (errorText) {
            statusElement.textContent = errorText;
        } else if (!enabled) {
            statusElement.textContent = 'Pilot off';
        } else if (status?.codex_available === false) {
            statusElement.textContent = 'codex unavailable';
        } else if (remote.running) {
            const pidText = remote.pid ? ` · pid ${remote.pid}` : '';
            statusElement.textContent = `remote-control running${pidText}`;
        } else {
            statusElement.textContent = 'Pilot on · stdio';
        }
        setChatToolHelp(statusElement, 'appServerStatus', errorText || statusElement.textContent);
    }

    renderAppServerModels();
    renderAppServerFeatures();
    renderAppServerThreads();
    syncChatToolsToggleState();
}

function setAppServerPanelEmpty(id, text) {
    const panel = document.getElementById(id);
    if (!panel) return;
    panel.innerHTML = '';
    const empty = document.createElement('div');
    empty.className = 'app-server-empty';
    empty.textContent = text;
    panel.appendChild(empty);
}

function createAppServerItem(title, meta = '') {
    const item = document.createElement('div');
    item.className = 'app-server-item';
    const main = document.createElement('div');
    main.className = 'app-server-item-main';
    const titleElement = document.createElement('div');
    titleElement.className = 'app-server-item-title';
    titleElement.textContent = title || 'Untitled';
    titleElement.title = title || 'Untitled';
    main.appendChild(titleElement);
    if (meta) {
        const metaElement = document.createElement('div');
        metaElement.className = 'app-server-item-meta';
        metaElement.textContent = meta;
        metaElement.title = meta;
        main.appendChild(metaElement);
    }
    item.appendChild(main);
    return { item, main };
}

function renderAppServerModels() {
    const panel = document.getElementById('codex-app-server-models');
    if (!panel) return;
    if (!state.settings.appServerPilotEnabled) {
        setAppServerPanelEmpty('codex-app-server-models', 'Off');
        return;
    }
    if (state.appServer.loading && state.appServer.models.length === 0) {
        setAppServerPanelEmpty('codex-app-server-models', 'Loading...');
        return;
    }
    const models = normalizeAppServerList(state.appServer.models).slice(0, 8);
    if (models.length === 0) {
        setAppServerPanelEmpty('codex-app-server-models', 'No models');
        return;
    }
    panel.innerHTML = '';
    models.forEach(model => {
        const title = model.displayName || model.display_name || model.model || model.id || 'model';
        const effort = model.defaultReasoningEffort || model.default_reasoning_effort || '';
        const hidden = model.hidden ? 'hidden' : '';
        const meta = [model.model || model.id || '', effort, hidden].filter(Boolean).join(' · ');
        panel.appendChild(createAppServerItem(title, meta).item);
    });
}

function renderAppServerFeatures() {
    const panel = document.getElementById('codex-app-server-features');
    if (!panel) return;
    if (!state.settings.appServerPilotEnabled) {
        setAppServerPanelEmpty('codex-app-server-features', 'Off');
        return;
    }
    if (state.appServer.loading && state.appServer.features.length === 0) {
        setAppServerPanelEmpty('codex-app-server-features', 'Loading...');
        return;
    }
    const features = normalizeAppServerList(state.appServer.features).slice(0, 12);
    if (features.length === 0) {
        setAppServerPanelEmpty('codex-app-server-features', 'No flags');
        return;
    }
    panel.innerHTML = '';
    features.forEach(feature => {
        const title = feature.displayName || feature.display_name || feature.name || 'feature';
        const enabled = feature.enabled === true ? 'on' : 'off';
        const stage = feature.stage || '';
        panel.appendChild(createAppServerItem(title, [stage, enabled].filter(Boolean).join(' · ')).item);
    });
}

function formatAppServerThreadTime(thread) {
    const raw = thread?.updatedAt ?? thread?.updated_at ?? thread?.createdAt ?? thread?.created_at;
    const numeric = Number(raw);
    if (Number.isFinite(numeric) && numeric > 0) {
        const millis = numeric < 1000000000000 ? numeric * 1000 : numeric;
        return formatTimestamp(new Date(millis).toISOString());
    }
    return '';
}

function renderAppServerThreadControls() {
    const enabled = Boolean(state.settings.appServerPilotEnabled);
    const busy = Boolean(state.appServer.loading);
    const searchInput = document.getElementById('codex-app-server-thread-search');
    const searchApply = document.getElementById('codex-app-server-thread-search-apply');
    const prevBtn = document.getElementById('codex-app-server-thread-prev');
    const nextBtn = document.getElementById('codex-app-server-thread-next');
    if (searchInput && document.activeElement !== searchInput) {
        searchInput.value = state.appServer.threadSearch || '';
    }
    if (searchInput) searchInput.disabled = !enabled || busy;
    if (searchApply) searchApply.disabled = !enabled || busy;
    if (prevBtn) prevBtn.disabled = !enabled || busy || state.appServer.threadCursorStack.length === 0;
    if (nextBtn) nextBtn.disabled = !enabled || busy || !state.appServer.threadNextCursor;
    setChatToolHelp(searchInput, 'threadSearchInput');
    setChatToolHelp(searchApply, 'threadSearch');
    setChatToolHelp(prevBtn, 'threadPrev');
    setChatToolHelp(nextBtn, 'threadNext');
}

function renderAppServerThreadDetail() {
    const panel = document.getElementById('codex-app-server-thread-detail');
    if (!panel) return;
    panel.innerHTML = '';
    if (!state.settings.appServerPilotEnabled || !state.appServer.selectedThreadId) {
        return;
    }
    if (state.appServer.threadDetailLoading) {
        const loading = document.createElement('div');
        loading.className = 'app-server-empty';
        loading.textContent = 'Loading thread...';
        panel.appendChild(loading);
        return;
    }
    if (state.appServer.threadDetailError) {
        const error = document.createElement('div');
        error.className = 'app-server-empty';
        error.textContent = state.appServer.threadDetailError;
        panel.appendChild(error);
        return;
    }
    const thread = state.appServer.threadDetail;
    if (!thread || typeof thread !== 'object') {
        const empty = document.createElement('div');
        empty.className = 'app-server-empty';
        empty.textContent = 'No thread detail';
        panel.appendChild(empty);
        return;
    }
    const head = document.createElement('div');
    head.className = 'app-server-thread-detail-head';
    const title = document.createElement('div');
    title.className = 'app-server-thread-detail-title';
    title.textContent = getAppServerThreadTitle(thread);
    title.title = title.textContent;
    head.appendChild(title);

    const actions = document.createElement('div');
    actions.className = 'app-server-thread-detail-actions';
    const turns = document.createElement('button');
    turns.type = 'button';
    turns.className = 'app-server-thread-action';
    turns.textContent = state.appServer.threadDetailIncludeTurns ? 'Refresh turns' : 'Turns';
    turns.disabled = state.appServer.threadDetailLoading;
    setChatToolHelp(turns, 'threadTurns');
    turns.addEventListener('click', event => {
        event.preventDefault();
        void readAppServerThread(state.appServer.selectedThreadId, { includeTurns: true });
    });
    actions.appendChild(createChatToolActionGroup(turns, 'threadTurns'));
    if (state.appServer.threadDetailNextCursor) {
        const moreTurns = document.createElement('button');
        moreTurns.type = 'button';
        moreTurns.className = 'app-server-thread-action';
        moreTurns.textContent = 'More';
        moreTurns.disabled = state.appServer.threadDetailLoading;
        setChatToolHelp(moreTurns, 'threadMoreTurns');
        moreTurns.addEventListener('click', event => {
            event.preventDefault();
            void loadMoreAppServerThreadTurns();
        });
        actions.appendChild(createChatToolActionGroup(moreTurns, 'threadMoreTurns'));
    }
    ['archive', 'compact', 'rollback'].forEach(actionId => {
        const preview = document.createElement('button');
        preview.type = 'button';
        preview.className = 'app-server-thread-action';
        preview.textContent = `${actionId} preview`;
        preview.disabled = state.appServer.threadDetailLoading;
        setChatToolHelp(preview, 'threadLifecyclePreview');
        preview.addEventListener('click', event => {
            event.preventDefault();
            void previewAppServerThreadLifecycle(state.appServer.selectedThreadId, actionId);
        });
        actions.appendChild(createChatToolActionGroup(preview, 'threadLifecyclePreview'));
    });
    head.appendChild(actions);
    panel.appendChild(head);

    const turnCount = state.appServer.threadDetailTurns.length;
    const meta = document.createElement('div');
    meta.className = 'app-server-thread-detail-meta';
    meta.textContent = [
        state.appServer.selectedThreadId,
        turnCount > 0 ? `${turnCount} turns` : '',
        state.appServer.threadDetailNextCursor ? 'more turns available' : '',
    ].filter(Boolean).join(' · ');
    panel.appendChild(meta);

    const pre = document.createElement('pre');
    pre.className = 'app-server-thread-detail-pre';
    pre.textContent = formatAppServerJson({
        thread,
        turns: state.appServer.threadDetailTurns,
    });
    panel.appendChild(pre);

    if (state.appServer.threadLifecyclePreview) {
        const lifecycle = document.createElement('pre');
        lifecycle.className = 'app-server-thread-detail-pre';
        lifecycle.textContent = formatAppServerJson({
            lifecycle_preview: state.appServer.threadLifecyclePreview
        }, 5000);
        panel.appendChild(lifecycle);
    }
}

function renderAppServerThreads() {
    const panel = document.getElementById('codex-app-server-threads');
    if (!panel) return;
    renderAppServerThreadControls();
    if (!state.settings.appServerPilotEnabled) {
        setAppServerPanelEmpty('codex-app-server-threads', 'Off');
        renderAppServerThreadDetail();
        return;
    }
    if (state.appServer.loading && state.appServer.threads.length === 0) {
        setAppServerPanelEmpty('codex-app-server-threads', 'Loading...');
        renderAppServerThreadDetail();
        return;
    }
    const threads = normalizeAppServerList(state.appServer.threads).slice(0, 20);
    if (threads.length === 0) {
        setAppServerPanelEmpty(
            'codex-app-server-threads',
            state.appServer.threadSearch ? 'No matching threads' : 'No threads'
        );
        renderAppServerThreadDetail();
        return;
    }
    panel.innerHTML = '';
    threads.forEach(thread => {
        const threadId = getAppServerThreadId(thread);
        const title = getAppServerThreadTitle(thread);
        const statusType = thread.status?.type || thread.status || '';
        const meta = [threadId, statusType, formatAppServerThreadTime(thread)].filter(Boolean).join(' · ');
        const { item } = createAppServerItem(title, meta);
        item.classList.toggle('is-selected', Boolean(threadId && threadId === state.appServer.selectedThreadId));
        const actions = document.createElement('div');
        actions.className = 'app-server-item-actions';
        const read = document.createElement('button');
        read.type = 'button';
        read.className = 'app-server-thread-action';
        read.textContent = 'Read';
        read.disabled = !threadId || state.appServer.threadDetailLoading;
        setChatToolHelp(read, 'threadRead');
        read.addEventListener('click', event => {
            event.preventDefault();
            void readAppServerThread(threadId, { includeTurns: false });
        });
        actions.appendChild(createChatToolActionGroup(read, 'threadRead'));
        const resume = document.createElement('button');
        resume.type = 'button';
        resume.className = 'app-server-thread-action';
        resume.textContent = 'Resume';
        resume.disabled = !threadId || state.appServer.loading;
        setChatToolHelp(resume, 'threadResume');
        resume.addEventListener('click', event => {
            event.preventDefault();
            void runAppServerThreadAction(threadId, 'resume');
        });
        actions.appendChild(createChatToolActionGroup(resume, 'threadResume'));
        const fork = document.createElement('button');
        fork.type = 'button';
        fork.className = 'app-server-thread-action';
        fork.textContent = 'Fork';
        fork.disabled = !threadId || state.appServer.loading;
        setChatToolHelp(fork, 'threadFork');
        fork.addEventListener('click', event => {
            event.preventDefault();
            void runAppServerThreadAction(threadId, 'fork');
        });
        actions.appendChild(createChatToolActionGroup(fork, 'threadFork'));
        item.appendChild(actions);
        panel.appendChild(item);
    });
    renderAppServerThreadDetail();
}

async function setAppServerPilotEnabled(enabled) {
    state.appServer.loading = true;
    state.appServer.error = '';
    renderAppServerPilot();
    try {
        const result = await fetchJson('/api/codex/settings', {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ app_server_pilot_enabled: Boolean(enabled) })
        });
        state.settings.appServerPilotEnabled = Boolean(result?.settings?.app_server_pilot_enabled);
        state.appServer.status = normalizeAppServerStatus(result?.app_server_status);
        if (!state.settings.appServerPilotEnabled) {
            state.appServer.models = [];
            state.appServer.features = [];
            state.appServer.threads = [];
            state.appServer.threadCursor = '';
            state.appServer.threadNextCursor = '';
            state.appServer.threadCursorStack = [];
            state.appServer.threadSearch = '';
            resetAppServerThreadDetail();
        }
        if (state.settings.appServerPilotEnabled) {
            await refreshAppServerPilot({ loadDetails: true });
        }
    } catch (error) {
        state.appServer.error = normalizeError(error, 'App Server pilot update failed');
    } finally {
        state.appServer.loading = false;
        renderAppServerPilot();
    }
}

async function refreshAppServerPilot({ loadDetails = false, showToastOnSuccess = false } = {}) {
    state.appServer.loading = true;
    state.appServer.error = '';
    renderAppServerPilot();
    try {
        const statusResult = await fetchJson('/api/codex/app-server/status', { cache: 'no-store' });
        state.appServer.status = normalizeAppServerStatus(statusResult?.status);
        state.settings.appServerPilotEnabled = Boolean(state.appServer.status?.pilot_enabled);
        if (loadDetails && state.settings.appServerPilotEnabled) {
            await loadAppServerPilotDetails();
        }
        if (showToastOnSuccess) {
            showToast('App Server 상태를 갱신했습니다.', { tone: 'success', durationMs: 2200 });
        }
    } catch (error) {
        state.appServer.error = normalizeError(error, 'App Server status failed');
    } finally {
        state.appServer.loading = false;
        renderAppServerPilot();
    }
}

async function loadAppServerPilotDetails() {
    const [modelsResult, featuresResult, threadsResult] = await Promise.allSettled([
        fetchJson('/api/codex/app-server/models?limit=20', { cache: 'no-store' }),
        fetchJson('/api/codex/app-server/features?limit=80', { cache: 'no-store' }),
        fetchJson(
            buildAppServerThreadsUrl({ searchTerm: state.appServer.threadSearch }),
            { cache: 'no-store' }
        )
    ]);
    if (modelsResult.status === 'fulfilled') {
        state.appServer.models = normalizeAppServerList(modelsResult.value?.models);
    }
    if (featuresResult.status === 'fulfilled') {
        state.appServer.features = normalizeAppServerList(featuresResult.value?.features);
    }
    if (threadsResult.status === 'fulfilled') {
        applyAppServerThreadsPayload(threadsResult.value, '', { resetStack: true });
    }
    const firstFailure = [modelsResult, featuresResult, threadsResult].find(item => item.status === 'rejected');
    if (firstFailure) {
        state.appServer.error = normalizeError(firstFailure.reason, 'App Server detail load failed');
    }
}

async function loadAppServerThreads({ cursor = '', pushCursor = false, resetStack = false } = {}) {
    if (!state.settings.appServerPilotEnabled) return;
    state.appServer.loading = true;
    state.appServer.error = '';
    renderAppServerPilot();
    try {
        const result = await fetchJson(
            buildAppServerThreadsUrl({ cursor, searchTerm: state.appServer.threadSearch }),
            { cache: 'no-store' }
        );
        applyAppServerThreadsPayload(result, cursor, { pushCursor, resetStack });
    } catch (error) {
        state.appServer.error = normalizeError(error, 'thread list failed');
    } finally {
        state.appServer.loading = false;
        renderAppServerPilot();
    }
}

async function applyAppServerThreadSearch(searchTerm) {
    state.appServer.threadSearch = String(searchTerm || '').trim();
    resetAppServerThreadDetail();
    await loadAppServerThreads({ cursor: '', resetStack: true });
}

async function loadNextAppServerThreads() {
    const nextCursor = state.appServer.threadNextCursor;
    if (!nextCursor) return;
    await loadAppServerThreads({ cursor: nextCursor, pushCursor: true });
}

async function loadPreviousAppServerThreads() {
    if (state.appServer.threadCursorStack.length === 0) return;
    const stack = [...state.appServer.threadCursorStack];
    const previousCursor = stack.pop() || '';
    state.appServer.threadCursorStack = stack;
    await loadAppServerThreads({ cursor: previousCursor });
}

async function startAppServerRemoteControl() {
    state.appServer.loading = true;
    state.appServer.error = '';
    renderAppServerPilot();
    try {
        const result = await fetchJson('/api/codex/app-server/remote-control/start', {
            method: 'POST',
            cache: 'no-store'
        });
        state.appServer.status = normalizeAppServerStatus(result?.status);
        await refreshAppServerPilot({ loadDetails: true });
    } catch (error) {
        state.appServer.error = normalizeError(error, 'remote-control start failed');
    } finally {
        state.appServer.loading = false;
        renderAppServerPilot();
    }
}

async function stopAppServerRemoteControl() {
    state.appServer.loading = true;
    state.appServer.error = '';
    renderAppServerPilot();
    try {
        const result = await fetchJson('/api/codex/app-server/remote-control/stop', {
            method: 'POST',
            cache: 'no-store'
        });
        state.appServer.status = normalizeAppServerStatus(result?.status);
    } catch (error) {
        state.appServer.error = normalizeError(error, 'remote-control stop failed');
    } finally {
        state.appServer.loading = false;
        renderAppServerPilot();
    }
}

async function readAppServerThread(threadId, { includeTurns = false } = {}) {
    const normalizedThreadId = String(threadId || '').trim();
    if (!normalizedThreadId) return;
    state.appServer.selectedThreadId = normalizedThreadId;
    state.appServer.threadDetailLoading = true;
    state.appServer.threadDetailError = '';
    state.appServer.threadDetailIncludeTurns = Boolean(includeTurns);
    renderAppServerPilot();
    try {
        const params = new URLSearchParams();
        if (includeTurns) {
            params.set('include_turns', '1');
        }
        const suffix = params.toString() ? `?${params.toString()}` : '';
        const result = await fetchJson(
            `/api/codex/app-server/threads/${encodeURIComponent(normalizedThreadId)}${suffix}`,
            { cache: 'no-store' }
        );
        state.appServer.threadDetail = result?.thread && typeof result.thread === 'object'
            ? result.thread
            : { id: normalizedThreadId };
        state.appServer.threadDetailTurns = normalizeAppServerList(result?.turns);
        state.appServer.threadDetailNextCursor = getAppServerNextCursor(result);
    } catch (error) {
        state.appServer.threadDetail = null;
        state.appServer.threadDetailTurns = [];
        state.appServer.threadDetailNextCursor = '';
        state.appServer.threadDetailError = normalizeError(error, 'thread read failed');
    } finally {
        state.appServer.threadDetailLoading = false;
        renderAppServerPilot();
    }
}

async function loadMoreAppServerThreadTurns() {
    const threadId = state.appServer.selectedThreadId;
    const cursor = state.appServer.threadDetailNextCursor;
    if (!threadId || !cursor) return;
    state.appServer.threadDetailLoading = true;
    state.appServer.threadDetailError = '';
    renderAppServerPilot();
    try {
        const params = new URLSearchParams();
        params.set('limit', '20');
        params.set('cursor', cursor);
        const result = await fetchJson(
            `/api/codex/app-server/threads/${encodeURIComponent(threadId)}/turns?${params.toString()}`,
            { cache: 'no-store' }
        );
        state.appServer.threadDetailTurns = [
            ...normalizeAppServerList(state.appServer.threadDetailTurns),
            ...normalizeAppServerList(result?.turns)
        ];
        state.appServer.threadDetailNextCursor = getAppServerNextCursor(result);
        state.appServer.threadDetailIncludeTurns = true;
    } catch (error) {
        state.appServer.threadDetailError = normalizeError(error, 'thread turns failed');
    } finally {
        state.appServer.threadDetailLoading = false;
        renderAppServerPilot();
    }
}

async function runAppServerThreadAction(threadId, action) {
    if (!threadId || (action !== 'resume' && action !== 'fork')) return;
    const actionLabel = action === 'resume' ? 'resume' : 'fork';
    const confirmed = window.confirm(`Thread ${threadId} ${actionLabel} 작업을 실행할까요?`);
    if (!confirmed) return;
    state.appServer.loading = true;
    state.appServer.error = '';
    renderAppServerPilot();
    try {
        const result = await fetchJson(
            `/api/codex/app-server/threads/${encodeURIComponent(threadId)}/${action}`,
            { method: 'POST', cache: 'no-store' }
        );
        const nextThread = result?.thread;
        if (nextThread && typeof nextThread === 'object') {
            const nextThreadId = getAppServerThreadId(nextThread);
            state.appServer.threads = [
                nextThread,
                ...normalizeAppServerList(state.appServer.threads)
                    .filter(thread => getAppServerThreadId(thread) !== nextThreadId)
            ];
            if (nextThreadId) {
                state.appServer.selectedThreadId = nextThreadId;
                state.appServer.threadDetail = nextThread;
                state.appServer.threadDetailTurns = [];
                state.appServer.threadDetailNextCursor = '';
                state.appServer.threadDetailIncludeTurns = false;
            }
        }
        showToast(`thread ${action} 완료`, { tone: 'success', durationMs: 2200 });
    } catch (error) {
        state.appServer.error = normalizeError(error, `thread ${action} failed`);
    } finally {
        state.appServer.loading = false;
        renderAppServerPilot();
    }
}

async function previewAppServerThreadLifecycle(threadId, action) {
    const normalizedThreadId = String(threadId || '').trim();
    const normalizedAction = String(action || '').trim();
    if (!normalizedThreadId || !normalizedAction) return;
    state.appServer.threadDetailLoading = true;
    state.appServer.threadDetailError = '';
    renderAppServerPilot();
    try {
        const result = await fetchJson(
            `/api/codex/app-server/threads/${encodeURIComponent(normalizedThreadId)}/lifecycle-preview`,
            {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                cache: 'no-store',
                body: JSON.stringify({ action: normalizedAction })
            }
        );
        const preview = result?.preview || {};
        state.appServer.threadLifecyclePreview = preview;
        showToast(`${preview.label || normalizedAction} preview ready`, {
            tone: 'success',
            durationMs: 2200
        });
    } catch (error) {
        state.appServer.threadDetailError = normalizeError(error, 'lifecycle preview failed');
    } finally {
        state.appServer.threadDetailLoading = false;
        renderAppServerPilot();
    }
}

function formatToolingJson(value, maxChars = 9000) {
    let text = '';
    try {
        text = JSON.stringify(value, null, 2);
    } catch (error) {
        text = String(value || '');
    }
    if (text.length <= maxChars) return text;
    return `${text.slice(0, maxChars)}\n... truncated ...`;
}

function setToolingPreviewText(elementId, value) {
    const element = document.getElementById(elementId);
    if (!element) return;
    const text = typeof value === 'string' ? value : formatToolingJson(value);
    element.textContent = text;
    element.classList.toggle('is-hidden', !text);
}

function createToolingCard(title, meta = '') {
    const card = document.createElement('div');
    card.className = 'tooling-card';
    const main = document.createElement('div');
    main.className = 'tooling-card-main';
    const titleElement = document.createElement('div');
    titleElement.className = 'tooling-card-title';
    titleElement.textContent = title || 'Untitled';
    main.appendChild(titleElement);
    if (meta) {
        const metaElement = document.createElement('div');
        metaElement.className = 'tooling-card-meta';
        metaElement.textContent = meta;
        main.appendChild(metaElement);
    }
    const actions = document.createElement('div');
    actions.className = 'tooling-card-actions';
    card.appendChild(main);
    card.appendChild(actions);
    return { card, actions };
}

function getCurrentPromptForTooling() {
    const input = document.getElementById('codex-chat-input');
    return String(input?.value || '').trim();
}

function renderToolingPanels() {
    renderSubagentPresets();
    renderSafetyPreview();
    renderMcpPreview();
    renderGithubActionPreview();
    setChatToolHelp(document.getElementById('codex-subagent-refresh'), 'subagentsSection');
    setChatToolHelp(document.getElementById('codex-skill-preview'), 'skillPreview');
    setChatToolHelp(document.getElementById('codex-skill-create'), 'skillCreate');
    setChatToolHelp(document.getElementById('codex-safety-preview-refresh'), 'safetySection');
    setChatToolHelp(document.getElementById('codex-mcp-preview-refresh'), 'mcpPreview');
    setChatToolHelp(document.getElementById('codex-mcp-save-preview'), 'mcpSave');
    setChatToolHelp(document.getElementById('codex-github-preview-refresh'), 'githubPreview');
    setChatToolHelp(document.getElementById('codex-github-save-preview'), 'githubSave');
}

async function ensureToolingPreviewData() {
    await Promise.allSettled([
        loadSubagentPresets(),
        loadSafetyPreview(),
        loadMcpPreview(),
        loadGithubActionPreview()
    ]);
}

async function loadSubagentPresets({ force = false } = {}) {
    if (!force && Array.isArray(state.tooling.subagentPresets) && state.tooling.subagentPresets.length > 0) {
        renderSubagentPresets();
        return state.tooling.subagentPresets;
    }
    try {
        const result = await fetchJson('/api/codex/tooling/subagents/presets', { cache: 'no-store' });
        state.tooling.subagentPresets = Array.isArray(result?.presets) ? result.presets : [];
        state.tooling.error = '';
    } catch (error) {
        state.tooling.error = normalizeError(error, 'subagent preset load failed');
    } finally {
        renderSubagentPresets();
    }
    return state.tooling.subagentPresets;
}

function renderSubagentPresets() {
    const panel = document.getElementById('codex-subagent-presets');
    if (!panel) return;
    panel.innerHTML = '';
    const presets = Array.isArray(state.tooling.subagentPresets) ? state.tooling.subagentPresets : [];
    if (presets.length === 0) {
        const empty = document.createElement('div');
        empty.className = 'app-server-empty';
        empty.textContent = state.tooling.error || 'No subagent presets';
        panel.appendChild(empty);
        return;
    }
    presets.forEach(preset => {
        const lanes = Array.isArray(preset.lanes) ? preset.lanes.length : Number(preset.max_parallel) || 0;
        const { card, actions } = createToolingCard(
            preset.label,
            [preset.description, `${lanes} lanes`, preset.estimated_cost].filter(Boolean).join(' · ')
        );
        const preview = document.createElement('button');
        preview.type = 'button';
        preview.className = 'app-server-thread-action';
        preview.textContent = 'Preview';
        setChatToolHelp(preview, 'subagentPreset');
        preview.addEventListener('click', event => {
            event.preventDefault();
            void previewSubagentPreset(preset.id);
        });
        actions.appendChild(createChatToolActionGroup(preview, 'subagentPreset'));

        const run = document.createElement('button');
        run.type = 'button';
        run.className = 'app-server-thread-action';
        run.textContent = 'Run';
        setChatToolHelp(run, 'subagentPreset');
        run.addEventListener('click', event => {
            event.preventDefault();
            void runSubagentPreset(preset.id);
        });
        actions.appendChild(createChatToolActionGroup(run, 'subagentPreset'));
        panel.appendChild(card);
    });
}

async function ensureActiveSessionForTooling() {
    if (state.activeSessionId) return state.activeSessionId;
    const session = await createSession(true);
    return session?.id || state.activeSessionId || '';
}

async function previewSubagentPreset(presetId) {
    try {
        const sessionId = await ensureActiveSessionForTooling();
        if (!sessionId) throw new Error('세션을 만들 수 없습니다.');
        const result = await fetchEncryptedChatPromptJson(
            `/api/codex/sessions/${encodeURIComponent(sessionId)}/subagent-presets/${encodeURIComponent(presetId)}/preview`,
            { prompt: getCurrentPromptForTooling() },
            { cache: 'no-store' }
        );
        state.tooling.subagentPreview = result?.preview || null;
        setToolingPreviewText('codex-subagent-preview', state.tooling.subagentPreview);
    } catch (error) {
        setToolingPreviewText('codex-subagent-preview', normalizeError(error, 'subagent preview failed'));
    }
}

async function runSubagentPreset(presetId) {
    try {
        const sessionId = await ensureActiveSessionForTooling();
        if (!sessionId) throw new Error('세션을 만들 수 없습니다.');
        const prompt = getCurrentPromptForTooling();
        const confirmed = window.confirm('선택한 preset의 subjob들을 병렬로 시작할까요? 각 lane은 별도 Codex 실행 비용이 발생합니다.');
        if (!confirmed) return;
        const result = await fetchEncryptedChatPromptJson(
            `/api/codex/sessions/${encodeURIComponent(sessionId)}/subagent-presets/${encodeURIComponent(presetId)}/run`,
            {
                prompt,
                attachments: getPendingAttachmentPayload()
            },
            { cache: 'no-store' }
        );
        state.tooling.subagentPreview = result;
        setToolingPreviewText('codex-subagent-preview', result);
        showToast(`subagent ${Number(result?.started_count) || 0}개 시작`, {
            tone: 'success',
            durationMs: 2600
        });
        await loadSessions({ preserveActive: true, reloadActive: true });
    } catch (error) {
        setToolingPreviewText('codex-subagent-preview', normalizeError(error, 'subagent run failed'));
    }
}

